  ('fire-eq-eng-moex-00003', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法有關第四類 公共危險物品之相關名詞定義，下列敘述何者正確？', '["易燃液體：指在一大氣壓時，閃火點在攝氏60度以下之液體", "可燃液體：指在一大氣壓時，閃火點超過攝氏93度未滿攝氏250度之液體", "第一石油類：指在一大氣壓時，閃火點未達攝氏70度者", "高閃火點物品：指閃火點在攝氏130度以上之第四類公共危險物品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00004', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '某液化石油氣容器串接使用場所串接使用量為100公斤，依公共危險物品及可燃性高壓氣體 製造儲存處理場所設置標準暨安全管理辦法規定，其使用之燃氣橡膠管長度不得超過 X 公 尺，且最小彎曲半徑為Y毫米以上，請問前述X、Y各為何？', '["X=1.2、Y=50", "X=1.5、Y=80", "X=1.6、Y=100", "X=1.8、Y=110"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00005', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '某化工廠欲新設一座室外儲槽儲存柴油（閃火點攝氏 60 度），該儲槽水平剖面最大直徑為 8公尺，經檢討該儲槽側板至其廠區境界線距離應有40公尺，惟實際量測僅有30公尺，若 欲於廠區境界線上設置防火水幕，依防火牆及防火水幕設置基準規定，請問防火水幕防護高 度應為何？', '["2公尺", "3公尺", "4公尺", "6公尺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00006', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法規定，有關可 燃性高壓氣體儲存場所之構造、設備及安全管理，下列敘述何者正確？', '["採用不燃材料構造之地面一層建築物，屋頂應以輕質金屬板或其他輕質不燃材料覆蓋，屋 簷並應距離地面2.5公尺以上", "保持攝氏50度以下之溫度；容器並應防止日光之直射", "周圍3公尺範圍內，應嚴禁煙火，且不得存放任何可燃性物質", "供3家以上販賣場所使用者，應製作平面配置圖，註明場所之面積、數量、編號及商號名 稱等資料，並懸掛於明顯處所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00007', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有一棟3層樓的建築物，每層樓地板面積皆為100平方公尺，且非為無開口樓層，各層用途 分別是一樓：診所，二樓、三樓：住宅，依複合用途建築物判斷基準，請問本棟建築物之用 途屬性為何？', '["複合用途建築物", "住宅", "單一用途建築物診所", "集合住宅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00008', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能認證實施要點規定，某業者申請防焰性能認證經審查合格，發給其認證合格登錄 編號 AE-01-1234，下列敘述何者錯誤？', '["登錄編號中AE係指業別，其中A為製造業", "登錄編號中AE係指業別，其中Ｅ為裁剪、縫製、安裝業", "登錄編號中01係指防焰物品種類，而01為防焰窗簾", "登錄編號中1234為序號"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00009', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，請問電影院之各樓層其應設之避難器具，在符合下 列何者之構造及相關設施等得予免設？', '["主要構造為防火構造，居室面向戶外部分，設有陽臺等有效避難設施，且該陽臺等設施設 有可通往地面之樓梯或通往他棟建築物之設施", "主要構造為防火構造，由居室或住戶可直接通往直通樓梯，且該居室或住戶所面向之直通 樓梯，設有隨時可自動關閉之甲種防火門（不含防火鐵捲門），且收容人員未滿500人", "使用之樓層，主要構造為防火構造且設有2座以上安全梯，且該樓層各部分均有2個以上 不同避難逃生路徑能通達安全梯", "使用之樓層，主要構造為防火構造並設有2座以上安全梯，且設有自動撒水設備或內部裝 修符合建築技術規則建築設計施工篇第88條規定者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00010', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，請就下列公共危險物品製造場所之面積、公共危險 物品數量或設備高度進行判定，何者屬顯著滅火困難場所？', '["總樓地板面積為900平方公尺", "第二類公共危險物品之硫磺、鐵粉、金屬粉、鎂合計數量達管制量120倍", "第四類公共危險物品之重油（閃火點攝氏150度）數量達管制量250倍，其操作溫度未滿 攝氏100度", "製造設備高於地面6.5公尺。其處理之公共危險物品為易燃液體（閃火點攝氏90度）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
